script:
(function() {
  'use strict';

  // Monetag Domain Check Candidates (Checks standard Monetag server endpoints)
  const MONETAG_DOMAINS = [
    'https://servomany.com/asrc?id=1',
    'https://native.propellerclick.com',
    'https://proparm.com'
  ];

  function triggerLock() {
    // Un-hide the popup
    const overlay = document.getElementById('anti-adblock-overlay');
    if (overlay) {
      overlay.style.display = 'flex';
      document.body.classList.add('adblock-active');

      // Blur underlying container view if present (Standard Blogger templates use id 'header-wrapper', 'main-wrapper', 'outer-wrapper')
      const wrappers = ['header-wrapper', 'main-wrapper', 'outer-wrapper', 'content-wrapper', 'body-layout', 'app-root'];
      wrappers.forEach(function(id) {
        const el = document.getElementById(id);
        if (el) {
          el.style.filter = 'blur(15px)';
          el.style.pointerEvents = 'none';
        }
      });
    }
  }

  // --- LAYER 1: DOM CHECK (Browser Extensions) ---
  function runDomCheck() {
    // Create a dummy fake advertisement bait element with common class names/triggers
    const adBait = document.createElement('div');
    adBait.innerHTML = ' ';
    adBait.className = 'adsbox ads-box doubleclick-ad ad-placement monetization-ad sponsored-banner';
    adBait.setAttribute('style', 'position: absolute; left: -9999px; top: -9999px; width: 1px; height: 1px;');
    document.body.appendChild(adBait);

    window.setTimeout(function() {
      // If the element is hidden (height/offset zero or display none), AdBlock has blocked it
      if (adBait.offsetHeight === 0 || adBait.clientWidth === 0 || window.getComputedStyle(adBait).display === 'none') {
        triggerLock();
      }
      document.body.removeChild(adBait);
    }, 150);
  }

  // --- LAYER 2: DNS CHECK (AdGuard / Private DNS Filters) ---
  function runDnsCheck() {
    // Pick a random primary Monetag endpoint to perform background DNS verification
    const testUrl = MONETAG_DOMAINS[Math.floor(Math.random() * MONETAG_DOMAINS.length)];

    // Execute a silent, low-footprint fetch request of the ad domain
    fetch(testUrl, {
      method: 'HEAD',
      mode: 'no-cors',
      cache: 'no-store',
      credentials: 'omit'
    })
    .then(function() {
      // Connected successfully! Ad server is reachable.
    })
    .catch(function(err) {
      // If a network connection error was triggered (AdGuard/DNS blocked standard requests), lock the site
      console.warn('DNS adblock resolution restriction active:', err);
      triggerLock();
    });
  }

  // Run dual-layer security scan as soon as document is ready
  if (document.readyState === 'complete' || document.readyState === 'interactive') {
    runDomCheck();
    runDnsCheck();
  } else {
    document.addEventListener('DOMContentLoaded', function() {
      runDomCheck();
      runDnsCheck();
    });
  }
})();
